// strategy logic redacted from this public copy.
// original performed proprietary analysis (Elliott Wave / FVG / confluence / sizing).
// replace with your own setup detection or LLM call.
const input = $input.first().json;
return [{ json: { ...input, _redacted: true } }];

const aggregated = $input.item.json;
const allSetups = Array.isArray(aggregated) ? aggregated : (aggregated.data || []);
const realSetups = allSetups.filter(s => !s._no_setups);
const now = new Date().toISOString().slice(0, 16).replace('T', ' ');
const count = realSetups.length;

if (count === 0) {
  const noSetupMsg = allSetups[0]?.message || 'No setups generated (confidence threshold not met or no FVG zones found).';
  return [{ json: { message: '📊 <b>BTMS SCAN</b> — ' + now + ' UTC\n\n⚠️ ' + noSetupMsg + '\n\nMarket conditions may not be suitable for intraday trading today.' } }];
}

const firstSetup = realSetups[0] || {};
const dirEmoji = firstSetup.direction === 'LONG' ? '📈' : '📉';

let msg = '📊 <b>BTMS SCAN COMPLETE — BTCUSDT</b>\n';
msg += '🕐 ' + now + ' UTC\n\n';
msg += dirEmoji + ' <b>DIRECTION: ' + (firstSetup.direction || 'N/A') + '</b>\n';
msg += '<i>' + (firstSetup.ew_context || '') + '</i>\n\n';

realSetups.forEach((s, i) => {
  const confPct = Math.round((s.confidence || 0) * 100);
  msg += '───── SETUP ' + (i + 1) + ' ─────\n';
  msg += 'Zone: $' + (s.entry_low || 0).toLocaleString() + ' – $' + (s.entry_high || 0).toLocaleString() + '\n';
  msg += '✅ Valid: ' + (s.valid_price || 0).toLocaleString() + ' | ❌ Invalid: ' + (s.invalid_price || 0).toLocaleString() + '\n';
  msg += 'SL: ' + (s.stop_loss || 0).toLocaleString() + ' | TP1: ' + (s.tp1 || 0).toLocaleString() + ' | TP2: ' + (s.tp2 || 0).toLocaleString() + '\n';
  msg += 'TF: ' + (s.entry_tf || '15M') + ' | Confidence: ' + confPct + '%\n';
  msg += 'FVG: ' + (s.fvg_description || '') + '\n';
  const confirmPrice = s.valid_price || (s.direction === 'LONG' ? s.entry_high : s.entry_low) || 0;
  const triggerDir = s.direction === 'LONG' ? 'Bullish' : 'Bearish';
  const triggerAction = s.direction === 'LONG' ? 'above' : 'below';
  msg += '🎯 Trigger: ' + triggerDir + ' ' + (s.entry_tf || '15M') + ' close ' + triggerAction + ' $' + confirmPrice.toLocaleString() + '\n\n';
});

msg += '✅ ' + count + ' setup' + (count !== 1 ? 's' : '') + ' saved to Notion';

return [{ json: { message: msg } }];

// Purpose: Extract current BTCUSDT price from Bybit v5 market/tickers response
// Input: Bybit API response with retCode, result.list array
// Output: { currentPrice: number, symbol: string, priceTimestamp: ISO8601 }

const body = $input.item.json;

// Bybit returns HTTP 200 even for API-level errors — check retCode explicitly
if (body.retCode !== 0) {
  throw new Error(
    `Bybit API error: retCode=${body.retCode}, msg=${body.retMsg}. ` +
    `Check category/symbol query params on the Fetch Live Price node.`
  );
}

const list = body.result && body.result.list;
if (!Array.isArray(list) || list.length === 0) {
  throw new Error(
    `Bybit returned empty ticker list. result=${JSON.stringify(body.result)}`
  );
}

const ticker = list[0];
if (ticker.lastPrice === undefined || ticker.lastPrice === null) {
  throw new Error(
    `ticker.lastPrice missing from Bybit response. Got ticker keys: ${Object.keys(ticker).join(', ')}`
  );
}

const currentPrice = parseFloat(ticker.lastPrice);
if (isNaN(currentPrice)) {
  throw new Error(`lastPrice '${ticker.lastPrice}' parsed as NaN — unexpected value from Bybit`);
}

return [{ json: { currentPrice, symbol: ticker.symbol || 'BTCUSDT', priceTimestamp: new Date().toISOString() } }];

const results = $input.item.json.results || [];
const currentPrice = $('Extract Price').item.json.currentPrice;

if (results.length === 0) {
  return [];
}

return results.map(page => {
  const props = page.properties;
  return { json: {
    notion_page_id: page.id,
    direction: props.Direction?.select?.name || 'LONG',
    entry_low: props['Entry Low']?.number || 0,
    entry_high: props['Entry High']?.number || 0,
    invalid_price: props['Invalid Price']?.number || 0,
    valid_price: props['Valid Price']?.number || 0,
    stop_loss: props['Stop Loss']?.number || 0,
    tp1: props['Take Profit 1']?.number || 0,
    tp2: props['Take Profit 2']?.number || 0,
    entry_tf: props['Entry TF']?.select?.name || '15M',
    fvg_description: props['FVG Description']?.rich_text?.[0]?.text?.content || '',
    ew_context: props['Elliott Wave Context']?.rich_text?.[0]?.text?.content || '',
    confidence: props.Confidence?.number || 0,
    paper_trade_id: props['Paper Trade ID']?.number || null,
    setup_name: props.Name?.title?.[0]?.text?.content || 'Unknown Setup',
    currentPrice
  }};
});

