const input = $input.first().json;
return [{ json: { ...input, _redacted: true } }];

const d = $input.first().json;
const now = new Date();
const pad = n => String(n).padStart(2,'0');

const direction = d.direction || 'UNKNOWN';
const entry = d.currentPrice;
const stopLoss = d.validation?.adjusted_sl || d.stop_loss;
const tp1 = d.validation?.adjusted_tp1 || d.tp1;
const confidence = d.validation?.confidence || 0;
const symbol = d.symbol || 'BTCUSDT';

const tradeName = `${symbol}-SCAN-${now.getUTCFullYear()}${pad(now.getUTCMonth()+1)}${pad(now.getUTCDate())}-${pad(now.getUTCHours())}${pad(now.getUTCMinutes())}`;
const stopLossPct = Math.abs((stopLoss - entry) / entry) * 100;

const body = {
  parent: { database_id: '' + $env.NOTION_TRADES_DB_ID + '' },
  properties: {
    'Trade Name': { title: [{ text: { content: tradeName } }] },
    'Symbol': { rich_text: [{ text: { content: symbol } }] },
    'Side': { select: { name: direction === 'LONG' ? 'LONG' : 'SHORT' } },
    'Status': { select: { name: 'OPEN' } },
    'Entry': { number: entry },
    'Stop Loss': { number: stopLoss },
    'Take Profit': { number: tp1 },
    'Risk Pct': { number: 3 },
    'Stop Loss Pct': { number: stopLossPct },
    'Confidence': { number: confidence },
    'Open Time': { date: { start: now.toISOString() } },
    'Notes': { rich_text: [{ text: { content: 'source=scan_watch|fvg=' + (d.fvg_description || '') } }] }
  }
};

const res = await fetch('https://api.notion.com/v1/pages', {
  method: 'POST',
  headers: {
    'Authorization': 'Bearer ' + $env.NOTION_TOKEN + '',
    'Notion-Version': '2022-06-28',
    'Content-Type': 'application/json'
  },
  body: JSON.stringify(body)
});

const page = await res.json();
return [{ json: { ...d, notion_trade_page_id: page.id, trade_name: tradeName } }];

